script.text:
      /* <flatten type="Javascript"> */
function init$StocktakingAdjustment$Filter(f) {f.getItem('so_ct')._idle = 9;}
function active$StocktakingAdjustment$Filter(f) {
  f._looking = f.getItem('so_ct')._controlBehavior;
  f._looking.add_loading(on$InventoryLookupFilter$Before$Loading);
  var o = f.getItem('ngay_ct1');
  o.focus();
  f.live(o);
}
function close$StocktakingAdjustment$Filter(f) {try {f._looking.remove_loading(on$InventoryLookupFilter$Before$Loading);} catch (ex) {}}
function on$InventoryLookupFilter$Before$Loading(sender, e) {
  var f = sender._element.parentForm;
  if ((!f.validFields('ngay_ct1')) || (!f.validFields('ngay_ct2'))) e.type.cancelEvent = true;
    else {
    var d1 = f.getItemValue('ngay_ct1'), d2 = f.getItemValue('ngay_ct2');
    a = [
      {Name: 'd1', Type: 'DateTime', Value: d1},
      {Name: 'd2', Type: 'DateTime', Value: d2}
    ];
    sender.set_memvars(a);
  }
}
function on$Filter$Retrieve$QueryComplete(f, id, n, s, i, l) {
  var g = f.grid, k = new Array();
  g._denyNew = g._deny$Unit;
  g._denyMessage = null;
  if (!g._denyNew) g._denyNew = l;
  g._denyEdit = g._denyDelete = l;
  g._voucherID = id;
  if (l == 1) g._denyMessage = f._language == 'v' ? 'Đã khóa số liệu, kiểm tra lại ngày khóa sổ.' : 'Data is locked, you must modify system locked date.';

  if (i) Array.add(k, {Name: 'ma_vt', Opr: 'like', Value: i + '%', Type: 'String', Ignore: false});
  if (s) Array.add(k, {Name: 'ma_kho', Opr: 'like', Value: s + '%', Type: 'String', Ignore: false});
  Array.add(k, {Name: 'stt_rec', Opr: '=', Value: id, Type: 'String', Ignore: false});

  g.set_externalKey(k);
  g._alterTitle = [null, [['%s', n.toUpperCase(), true]]];
}
/* </flatten> */
